    this.scene.add(this.paintbrushMarkRoot);
    this.camera.add(this.carriedPlateAnchor);
    this.carriedPlateAnchor.position.set(0.56, -0.48, -0.98);
    this.carriedPlateAnchor.rotation.set(-0.08, -0.34, -0.14);
